import { useMemo, useState } from "react";
import { artifactDownloadUrl, artifactInlineUrl } from "../../api/client";
import type { ArtifactOut, ArtifactRef } from "../../api/types";
import "./ArtifactsPanel.css";

interface ArtifactsPanelProps {
  /** Artifacts from the just-completed run (carry the producing node). */
  runArtifacts: ArtifactOut[];
  /** All artifacts persisted for the chat (survive reopen / restart). */
  chatArtifacts: ArtifactRef[];
}

interface ArtifactItem {
  artifact_id: string;
  filename: string;
  mime: string;
  size: number;
  node_id: string | null;
}

export function ArtifactsPanel({ runArtifacts, chatArtifacts }: ArtifactsPanelProps) {
  // Merge by id; the run's artifacts win (they carry node_id), then any extra
  // persisted ones are appended. Newest-run-first feels right for a side panel.
  const items = useMemo<ArtifactItem[]>(() => {
    const seen = new Set<string>();
    const merged: ArtifactItem[] = [];
    for (const a of runArtifacts) {
      if (seen.has(a.artifact_id)) continue;
      seen.add(a.artifact_id);
      merged.push(a);
    }
    for (const a of chatArtifacts) {
      if (seen.has(a.artifact_id)) continue;
      seen.add(a.artifact_id);
      merged.push({ artifact_id: a.artifact_id, filename: a.filename, mime: a.mime, size: a.size, node_id: null });
    }
    return merged;
  }, [runArtifacts, chatArtifacts]);

  return (
    <section className="artifacts" aria-label="Artifacts">
      <header className="artifacts-header">
        <h2 className="artifacts-title">Artifacts</h2>
        <span className="artifacts-count">{items.length}</span>
      </header>
      <div className="artifacts-body">
        {items.length === 0 ? (
          <p className="artifacts-empty">Files produced by a run appear here — preview inline or download.</p>
        ) : (
          <ul className="artifacts-list">
            {items.map((item) => (
              <ArtifactCard key={item.artifact_id} item={item} />
            ))}
          </ul>
        )}
      </div>
    </section>
  );
}

function ArtifactCard({ item }: { item: ArtifactItem }) {
  const [open, setOpen] = useState(false);
  return (
    <li className="artifact-card">
      <div className="artifact-row">
        <div className="artifact-meta">
          <span className="artifact-name">{item.filename}</span>
          <span className="artifact-sub">
            {formatBytes(item.size)}
            {item.node_id ? ` · ${item.node_id}` : ""}
          </span>
        </div>
        <div className="artifact-actions">
          <button
            type="button"
            className="artifact-btn"
            aria-expanded={open}
            onClick={() => setOpen((v) => !v)}
          >
            {open ? "Hide" : "Preview"}
          </button>
          <a className="artifact-btn artifact-download" href={artifactDownloadUrl(item.artifact_id)} download={item.filename}>
            Download
          </a>
        </div>
      </div>
      {open && (
        <iframe
          className="artifact-preview"
          title={`Preview of ${item.filename}`}
          src={artifactInlineUrl(item.artifact_id)}
          sandbox=""
        />
      )}
    </li>
  );
}

function formatBytes(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`;
  const kb = bytes / 1024;
  if (kb < 1024) return `${kb.toFixed(1)} KB`;
  return `${(kb / 1024).toFixed(1)} MB`;
}
